package pages;import org.openqa.selenium.By;import org.openqa.selenium.WebDriver;public class CrearPlatoPage {    private WebDriver driver;    public CrearPlatoPage(WebDriver driver) {        this.driver = driver;    }    public void ingresarNombre(String nombre) {        driver.findElement(By.name("name")).sendKeys(nombre);    }    public void ingresarDescripcion(String descripcion) {        driver.findElement(By.name("description"))                .sendKeys(descripcion);    }    public void ingresarPrecio(String precio) {        driver.findElement(By.name("price"))                .sendKeys(precio);    }    public void crearPlato() {        driver.findElement(                By.xpath("//button[text()='Crear']")        ).click();    }}